		T rb = query(a, b, k * 2 + 2, (l + r) / 2, r);

		update_node(k);

		if (cmp(lb, rb))return lb;

		return rb;

	}

	inline void update(int a, int b, T x) {

		update(a, b, x, 0, 0, n);

